    {"soru": "x+3 > 0, 2x-4 < 0 ve x tam sayi ise x kac degerdir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Esitsizlikler", "aciklama": "x>-3 ve x<2. Tam sayilar: -2,-1,0,1. 4 tane. Duzeltme: Soru x+3>0 => x>-3, 2x-4<0 => x<2. x=-2,-1,0,1. 4 tane."},
    {"soru": "5-2x >= 1 esitsizliginin cozum kumesi nedir?", "secenekler": ["A) x<=2", "B) x>=2", "C) x<=-2", "D) x>=-2"], "cevap": 0, "konu": "Esitsizlikler", "aciklama": "-2x>=-4, x<=2"},
    {"soru": "x/4 + x/2 < 3 esitsizliginin cozum kumesi nedir?", "secenekler": ["A) x<2", "B) x<3", "C) x<4", "D) x<6"], "cevap": 2, "konu": "Esitsizlikler", "aciklama": "x/4+2x/4=3x/4<3, x<4"},
    {"soru": "Bir topun fiyati 15 TL'dir. 200 TL ile en fazla kac top alinabilir?", "secenekler": ["A) 12", "B) 13", "C) 14", "D) 15"], "cevap": 1, "konu": "Esitsizlikler", "aciklama": "15x<=200, x<=13.33. En fazla 13"},
    {"soru": "3x > x+8 esitsizliginin cozum kumesi nedir?", "secenekler": ["A) x>2", "B) x>4", "C) x>6", "D) x>8"], "cevap": 1, "konu": "Esitsizlikler", "aciklama": "2x>8, x>4"},
    {"soru": "x-2 <= 5 VE x+1 >= 3 sisteminin cozum kumesi nedir?", "secenekler": ["A) 2<=x<=7", "B) 3<=x<=5", "C) 1<=x<=7", "D) 2<=x<=5"], "cevap": 0, "konu": "Esitsizlikler", "aciklama": "x<=7 ve x>=2 => 2<=x<=7"},
    {"soru": "2(3x-1) < 4(x+2) esitsizliginin cozum kumesi nedir?", "secenekler": ["A) x<2", "B) x<3", "C) x<5", "D) x<10"], "cevap": 2, "konu": "Esitsizlikler", "aciklama": "6x-2<4x+8, 2x<10, x<5"},
