    {"soru": "Bir ogrenci 100 soruluk testte dogru sayisinin 3 kati yanlis sayisindan fazla olmasini istiyor. En az kac dogru yapmalidir?", "secenekler": ["A) 20", "B) 25", "C) 26", "D) 30"], "cevap": 2, "konu": "Esitsizlikler", "aciklama": "d+y=100, 3d>y=100-d, 4d>100, d>25. En az 26"},
    {"soru": "x^2 < 16 esitsizligini saglayan tam sayilar kac tanedir?", "secenekler": ["A) 5", "B) 6", "C) 7", "D) 8"], "cevap": 2, "konu": "Esitsizlikler", "aciklama": "-4<x<4. Tam sayilar: -3,-2,-1,0,1,2,3 => 7 tane"},
