    {"soru": "3x-2 > 0 VE 5x+1 < 16 esitsizlik sisteminin tam sayi cozumu kac tanedir?", "secenekler": ["A) 1", "B) 2", "C) 3", "D) 4"], "cevap": 1, "konu": "Esitsizlikler", "aciklama": "x>2/3 ve x<3. Tam sayilar: 1,2. 2 tane"},
    {"soru": "Bir zarla atista 3'ten buyuk sayi gelme olasiligi kactir?", "secenekler": ["A) 1/6", "B) 1/3", "C) 1/2", "D) 2/3"], "cevap": 2, "konu": "Olasilik", "aciklama": "4,5,6 => 3 sonuc. 3/6=1/2"},
