    {"soru": "10 kisiden 3'u secilecek. Kac farkli secim yapilabilir?", "secenekler": ["A) 30", "B) 60", "C) 120", "D) 720"], "cevap": 2, "konu": "Olasilik", "aciklama": "C(10,3)=10!/(3!x7!)=120"},
