    {"soru": "2x+3y=12, x=3 ise y kactir?", "secenekler": ["A) 1", "B) 2", "C) 3", "D) 4"], "cevap": 1, "konu": "Denklemler", "aciklama": "6+3y=12, 3y=6, y=2"},
    {"soru": "4x-5=2x+7 denkleminde x kactir?", "secenekler": ["A) 4", "B) 5", "C) 6", "D) 7"], "cevap": 2, "konu": "Denklemler", "aciklama": "2x=12, x=6"},
    {"soru": "(x+2)/3 = 4 denkleminde x kactir?", "secenekler": ["A) 6", "B) 8", "C) 10", "D) 14"], "cevap": 2, "konu": "Denklemler", "aciklama": "x+2=12, x=10"},
    {"soru": "Bir sayinin 2 kati ile 3 katinin toplami 35 ise sayi kactir?", "secenekler": ["A) 5", "B) 7", "C) 10", "D) 12"], "cevap": 1, "konu": "Denklemler", "aciklama": "2x+3x=35, 5x=35, x=7"},
    {"soru": "x-4=2(x-7) denkleminde x kactir?", "secenekler": ["A) 6", "B) 8", "C) 10", "D) 12"], "cevap": 2, "konu": "Denklemler", "aciklama": "x-4=2x-14, 10=x"},
    {"soru": "2x+y=8, x+2y=7 denklem sisteminde x+y kactir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Denklemler", "aciklama": "Toplam: 3x+3y=15, x+y=5"},
    {"soru": "3x/4 = 9 denkleminde x kactir?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 15"], "cevap": 2, "konu": "Denklemler", "aciklama": "3x=36, x=12"},
    {"soru": "Bir dikdortgenin cevresi 30 cm, uzun kenari kisa kenarinin 2 katidir. Uzun kenar kac cm?", "secenekler": ["A) 5", "B) 8", "C) 10", "D) 12"], "cevap": 2, "konu": "Denklemler", "aciklama": "2(x+2x)=30, 6x=30, x=5. Uzun kenar=10"},
    {"soru": "x+3y=11, 2x-y=1 denklem sisteminde x kactir?", "secenekler": ["A) 1", "B) 2", "C) 3", "D) 4"], "cevap": 1, "konu": "Denklemler", "aciklama": "2. denklemden y=2x-1. x+3(2x-1)=11, x+6x-3=11, 7x=14, x=2"},
    {"soru": "5(x-1)-3(x+2)=1 denkleminde x kactir?", "secenekler": ["A) 4", "B) 5", "C) 6", "D) 7"], "cevap": 2, "konu": "Denklemler", "aciklama": "5x-5-3x-6=1, 2x-11=1, 2x=12, x=6"},
    {"soru": "Bir sayinin yarisi ile ucte birinin toplami 10 ise sayi kactir?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 15"], "cevap": 2, "konu": "Denklemler", "aciklama": "x/2+x/3=10, 5x/6=10, x=12"},
    {"soru": "2x-3=0 denkleminde x kactir?", "secenekler": ["A) 3/2", "B) 2/3", "C) -3/2", "D) 3"], "cevap": 0, "konu": "Denklemler", "aciklama": "2x=3, x=3/2"},
    {"soru": "x^2=49 denkleminin pozitif koku kactir?", "secenekler": ["A) 5", "B) 6", "C) 7", "D) 8"], "cevap": 2, "konu": "Denklemler", "aciklama": "x=7"},
    {"soru": "3x+2y=16, x-y=2 denklem sisteminde y kactir?", "secenekler": ["A) 1", "B) 2", "C) 3", "D) 4"], "cevap": 1, "konu": "Denklemler", "aciklama": "x=y+2. 3(y+2)+2y=16, 5y+6=16, y=2"},
    {"soru": "Ali'nin parasinin 3 kati, 20 TL fazlasidir. Ali'nin parasi kac TL'dir?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 15"], "cevap": 1, "konu": "Denklemler", "aciklama": "3x=x+20, 2x=20, x=10"},
    {"soru": "Babasi Ali'den 30 yas buyuk. 5 yil sonra babasi Ali'nin 3 kati olacak. Ali kac yasinda?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 15"], "cevap": 1, "konu": "Denklemler", "aciklama": "(x+30+5)=3(x+5), x+35=3x+15, 20=2x, x=10"},
    {"soru": "4(x+3)=3(x+5) denkleminde x kactir?", "secenekler": ["A) 2", "B) 3", "C) 5", "D) 7"], "cevap": 1, "konu": "Denklemler", "aciklama": "4x+12=3x+15, x=3"},
    {"soru": "x+y=8, xy=15 ise x^2+y^2 kactir?", "secenekler": ["A) 30", "B) 34", "C) 38", "D) 49"], "cevap": 1, "konu": "Denklemler", "aciklama": "x^2+y^2=(x+y)^2-2xy=64-30=34"},
    {"soru": "Uc ardisik sayinin toplami 42 ise en kucugu kactir?", "secenekler": ["A) 12", "B) 13", "C) 14", "D) 15"], "cevap": 1, "konu": "Denklemler", "aciklama": "n+(n+1)+(n+2)=42, 3n+3=42, n=13"},
    {"soru": "2x+5=3x-1 denkleminde x kactir?", "secenekler": ["A) 4", "B) 5", "C) 6", "D) 7"], "cevap": 2, "konu": "Denklemler", "aciklama": "6=x"},
    {"soru": "x/2 - x/3 = 2 denkleminde x kactir?", "secenekler": ["A) 6", "B) 8", "C) 10", "D) 12"], "cevap": 3, "konu": "Denklemler", "aciklama": "3x/6-2x/6=2, x/6=2, x=12"},
    {"soru": "Toplami 50, farki 14 olan iki sayi nedir?", "secenekler": ["A) 15 ve 35", "B) 18 ve 32", "C) 20 ve 30", "D) 22 ve 28"], "cevap": 1, "konu": "Denklemler", "aciklama": "x+y=50, x-y=14 => x=32, y=18"},
    {"soru": "3(x-2)+2(x+1)=16 denkleminde x kactir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 1, "konu": "Denklemler", "aciklama": "3x-6+2x+2=16, 5x-4=16, 5x=20, x=4"},
