    {"soru": "2x-y=5, x+y=7 denklem sisteminde x kactir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 1, "konu": "Denklemler", "aciklama": "Toplam: 3x=12, x=4"},
    {"soru": "Bir kutunun icinde x tane bilye var. 7 bilye eklenince toplam 3 katina esit oluyor. x kactir?", "secenekler": ["A) 3", "B) 3.5", "C) 4", "D) 7"], "cevap": 1, "konu": "Denklemler", "aciklama": "x+7=3x, 7=2x, x=3.5"},
