    {"soru": "x+2y=10, 3x+2y=18 denklem sisteminde x kactir?", "secenekler": ["A) 2", "B) 3", "C) 4", "D) 5"], "cevap": 2, "konu": "Denklemler", "aciklama": "Cikaralim: 2x=8, x=4"},
    {"soru": "Bir sayinin 2/3'u 18 ise sayinin kendisi kactir?", "secenekler": ["A) 12", "B) 18", "C) 24", "D) 27"], "cevap": 3, "konu": "Denklemler", "aciklama": "2x/3=18, x=27"},
