    {"soru": "2x+3=x+8 denkleminde x kactir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Denklemler", "aciklama": "x=5"},
    {"soru": "x+y=12, 2x-y=3 denklem sisteminde y kactir?", "secenekler": ["A) 5", "B) 6", "C) 7", "D) 8"], "cevap": 2, "konu": "Denklemler", "aciklama": "Toplam: 3x=15, x=5. y=12-5=7"},
    {"soru": "Bir sayinin 3 kati, o sayinin 10 fazlasidir. Sayi kactir?", "secenekler": ["A) 3", "B) 5", "C) 7", "D) 10"], "cevap": 1, "konu": "Denklemler", "aciklama": "3x=x+10, 2x=10, x=5"},
    {"soru": "5x-2(x+3)=9 denkleminde x kactir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Denklemler", "aciklama": "5x-2x-6=9, 3x=15, x=5"},
    {"soru": "Bir sinifta kiz sayisi erkek sayisinin 2 fazlasidir. Toplamda 28 kisi varsa kac erkek vardir?", "secenekler": ["A) 12", "B) 13", "C) 14", "D) 15"], "cevap": 1, "konu": "Denklemler", "aciklama": "x+(x+2)=28, 2x=26, x=13"},
