    {"soru": "Iki sayinin farki 8, buyugunun kucuge orani 3 ise buyuk sayi kactir?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 16"], "cevap": 2, "konu": "Denklemler", "aciklama": "x-y=8, x=3y. 3y-y=8, 2y=8, y=4. x=12"},
    {"soru": "3x+4y=25, x+4y=15 denklem sisteminde x kactir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Denklemler", "aciklama": "Cikaralim: 2x=10, x=5"},
    {"soru": "10x-3(2x+1)=13 denkleminde x kactir?", "secenekler": ["A) 2", "B) 3", "C) 4", "D) 5"], "cevap": 2, "konu": "Denklemler", "aciklama": "10x-6x-3=13, 4x=16, x=4"},
    {"soru": "Bir isci 3 gunde 12 parca uretir. 45 parca icin kac gun gerekir?", "secenekler": ["A) 9", "B) 10.5", "C) 11.25", "D) 12"], "cevap": 2, "konu": "Denklemler", "aciklama": "3/12=x/45, x=3x45/12=11.25 gun. Duzeltme: Gunluk 4 parca. 45/4=11.25"},
    {"soru": "ABC ucgeninde A=50, B=70 ise C acisi kactir?", "secenekler": ["A) 40", "B) 50", "C) 60", "D) 80"], "cevap": 2, "konu": "Ucgenler", "aciklama": "A+B+C=180. C=180-50-70=60"},
    {"soru": "Bir ucgenin iki kenari 5 cm ve 8 cm ise ucuncu kenar hangisi olamaz?", "secenekler": ["A) 4", "B) 7", "C) 12", "D) 14"], "cevap": 3, "konu": "Ucgenler", "aciklama": "Ucgen esitsizligi: 3<x<13. 14>13 olamaz"},
    {"soru": "Dik ucgende dik kenarlar 3 cm ve 4 cm ise hipotenus kac cm?", "secenekler": ["A) 5", "B) 6", "C) 7", "D) 8"], "cevap": 0, "konu": "Ucgenler", "aciklama": "Pisagor: 3^2+4^2=25. Hipotenus=5"},
    {"soru": "Bir ucgende en buyuk aci 90 dereceden buyukse bu ucgen ne tur ucgendir?", "secenekler": ["A) Dar", "B) Dik", "C) Genis", "D) Eskenar"], "cevap": 2, "konu": "Ucgenler", "aciklama": "90'dan buyuk aci varsa genis acili ucgen"},
    {"soru": "Eskenar ucgenin bir acisi kac derecedir?", "secenekler": ["A) 45", "B) 60", "C) 90", "D) 120"], "cevap": 1, "konu": "Ucgenler", "aciklama": "Eskenar ucgende her aci 60 derece"},
    {"soru": "Bir ucgende kenarlar 6, 8, 10 ise bu ucgen ne tur ucgendir?", "secenekler": ["A) Dar acili", "B) Dik acili", "C) Genis acili", "D) Eskenar"], "cevap": 1, "konu": "Ucgenler", "aciklama": "6^2+8^2=100=10^2. Dik acili"},
    {"soru": "Ikizkenar ucgende taban acilari 50'ser derece ise tepe acisi kac derecedir?", "secenekler": ["A) 50", "B) 60", "C) 70", "D) 80"], "cevap": 3, "konu": "Ucgenler", "aciklama": "180-50-50=80"},
    {"soru": "Kenar uzunluklari 5, 12, 13 olan ucgen ne tur ucgendir?", "secenekler": ["A) Dar", "B) Dik", "C) Genis", "D) Ikizkenar"], "cevap": 1, "konu": "Ucgenler", "aciklama": "5^2+12^2=25+144=169=13^2. Dik"},
    {"soru": "Bir ucgenin ic acilarinin toplami kac derecedir?", "secenekler": ["A) 90", "B) 180", "C) 270", "D) 360"], "cevap": 1, "konu": "Ucgenler", "aciklama": "Ucgenin ic acilar toplami=180"},
    {"soru": "Bir ucgende dis aci 120 ise, bu aciya komsu ic aci kac derecedir?", "secenekler": ["A) 30", "B) 60", "C) 120", "D) 150"], "cevap": 1, "konu": "Ucgenler", "aciklama": "Ic aci + Dis aci = 180. 180-120=60"},
    {"soru": "Dik ucgende bir dar aci 35 ise diger dar aci kactir?", "secenekler": ["A) 35", "B) 45", "C) 55", "D) 65"], "cevap": 2, "konu": "Ucgenler", "aciklama": "90+35+x=180, x=55"},
    {"soru": "ABC ucgeninde AB=AC=7 cm, BC=10 cm. Bu ucgenin turu nedir?", "secenekler": ["A) Eskenar", "B) Ikizkenar", "C) Cesitkenar", "D) Dik"], "cevap": 1, "konu": "Ucgenler", "aciklama": "Iki kenar esit: ikizkenar"},
    {"soru": "Bir ucgenin kenarlari 3, 4, 6 ise bu ucgen ne tur acili ucgendir?", "secenekler": ["A) Dar", "B) Dik", "C) Genis", "D) Belirlenemez"], "cevap": 2, "konu": "Ucgenler", "aciklama": "6^2=36 > 3^2+4^2=25. Genis acili"},
    {"soru": "Dik ucgende hipotenus 13, bir kenar 5 ise diger kenar kactir?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 14"], "cevap": 2, "konu": "Ucgenler", "aciklama": "13^2-5^2=169-25=144. Karekoku(144)=12"},
    {"soru": "Bir ucgende acilarin olculeri 2x, 3x, 4x ise en buyuk aci kactir?", "secenekler": ["A) 40", "B) 60", "C) 80", "D) 100"], "cevap": 2, "konu": "Ucgenler", "aciklama": "9x=180, x=20. En buyuk=4x20=80"},
    {"soru": "Bir ucgenin dis acilarinin toplami kac derecedir?", "secenekler": ["A) 180", "B) 270", "C) 360", "D) 540"], "cevap": 2, "konu": "Ucgenler", "aciklama": "Dis acilar toplami her zaman 360"},
    {"soru": "ABC ve DEF ucgenleri benzer. AB=6, DE=9, BC=8 ise EF kactir?", "secenekler": ["A) 10", "B) 12", "C) 14", "D) 16"], "cevap": 1, "konu": "Ucgenler", "aciklama": "6/9=8/EF, EF=8x9/6=12"},
    {"soru": "30-60-90 ucgeninde kisa kenar 5 ise hipotenus kactir?", "secenekler": ["A) 5*Karekoku(3)", "B) 10", "C) 10*Karekoku(3)", "D) 15"], "cevap": 1, "konu": "Ucgenler", "aciklama": "30-60-90'da hipotenus = 2 x kisa kenar = 10"},
    {"soru": "Ikizkenar dik ucgenin hipotenusunu 10 ise dik kenar kactir?", "secenekler": ["A) 5", "B) 5*Karekoku(2)", "C) 10*Karekoku(2)", "D) 10"], "cevap": 1, "konu": "Ucgenler", "aciklama": "a^2+a^2=100, 2a^2=100, a=5*Karekoku(2)"},
    {"soru": "Ucgenin iki ic acisi 45 ve 65 ise ucuncu dis aci kactir?", "secenekler": ["A) 70", "B) 110", "C) 120", "D) 130"], "cevap": 1, "konu": "Ucgenler", "aciklama": "Ic aci=180-45-65=70. Dis aci=180-70=110"},
    {"soru": "Bir ucgende kenarlar 7, 24, 25 ise bu ucgen dik acili midir?", "secenekler": ["A) Evet, dik acili", "B) Hayir, dar acili", "C) Hayir, genis acili", "D) Belirlenemez"], "cevap": 0, "konu": "Ucgenler", "aciklama": "7^2+24^2=49+576=625=25^2. Dik acili"},
    {"soru": "ABC ucgeninde A=40, B acisinin dis acisi 100 ise C kactir?", "secenekler": ["A) 40", "B) 60", "C) 80", "D) 100"], "cevap": 1, "konu": "Ucgenler", "aciklama": "B=180-100=80. C=180-40-80=60"},
    {"soru": "Kenar uzunluklari 5, 5, 5 olan ucgen ne tur ucgendir?", "secenekler": ["A) Ikizkenar", "B) Cesitkenar", "C) Eskenar", "D) Dik"], "cevap": 2, "konu": "Ucgenler", "aciklama": "Uc kenar esit: eskenar"},
    {"soru": "Bir ucgenin iki kenari 9 ve 12 ise ucuncu kenar en az kac tam sayi olabilir?", "secenekler": ["A) 2", "B) 3", "C) 4", "D) 5"], "cevap": 2, "konu": "Ucgenler", "aciklama": "x>12-9=3. En az tam sayi=4"},
    {"soru": "Dik ucgende kenarlar 8, 15 ise hipotenus kactir?", "secenekler": ["A) 15", "B) 17", "C) 19", "D) 23"], "cevap": 1, "konu": "Ucgenler", "aciklama": "8^2+15^2=64+225=289. Karekoku(289)=17"},
    {"soru": "ABC ucgeninde AB/DE=BC/EF=AC/DF=2 ise ABC'nin alani DEF'in alaninin kac katidir?", "secenekler": ["A) 2", "B) 4", "C) 6", "D) 8"], "cevap": 1, "konu": "Ucgenler", "aciklama": "Benzer ucgenlerde alan orani = k^2 = 2^2 = 4"},
    {"soru": "Eskenar ucgenin cevresi 36 cm ise bir kenari kac cm?", "secenekler": ["A) 9", "B) 10", "C) 12", "D) 18"], "cevap": 2, "konu": "Ucgenler", "aciklama": "36/3=12"},
    {"soru": "Bir ucgende acilarin olculeri x, x+20, x+40 ise en kucuk aci kactir?", "secenekler": ["A) 30", "B) 40", "C) 50", "D) 60"], "cevap": 1, "konu": "Ucgenler", "aciklama": "3x+60=180, x=40"},
    {"soru": "Dik ucgende dik kenarlar 9 ve 12 ise alan kac cm^2?", "secenekler": ["A) 36", "B) 48", "C) 54", "D) 108"], "cevap": 2, "konu": "Ucgenler", "aciklama": "Alan=(9x12)/2=54"},
    {"soru": "5-12-13 dik ucgenine benzer ucgenin hipotenusunu 26 ise kisa kenari kactir?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 14"], "cevap": 1, "konu": "Ucgenler", "aciklama": "26/13=2. Kisa kenar=5x2=10"},
    {"soru": "Bir ucgende iki aci esit ve her biri 70 derece ise ucuncu aci kactir?", "secenekler": ["A) 30", "B) 40", "C) 50", "D) 70"], "cevap": 1, "konu": "Ucgenler", "aciklama": "180-70-70=40"},
    {"soru": "Ucgen esitsizligine gore 4, 5 ve x icin x tam sayi ise kac farkli deger alir?", "secenekler": ["A) 5", "B) 7", "C) 8", "D) 9"], "cevap": 1, "konu": "Ucgenler", "aciklama": "1<x<9 => x=2,3,4,5,6,7,8 => 7 deger"},
    {"soru": "Dik ucgende hipotenus 10, bir kenar 6 ise diger kenar kactir?", "secenekler": ["A) 4", "B) 6", "C) 8", "D) 10"], "cevap": 2, "konu": "Ucgenler", "aciklama": "10^2-6^2=100-36=64. Karekoku(64)=8"},
    {"soru": "45-45-90 ucgeninde bir dik kenar 7 ise hipotenus kactir?", "secenekler": ["A) 7", "B) 7*Karekoku(2)", "C) 7*Karekoku(3)", "D) 14"], "cevap": 1, "konu": "Ucgenler", "aciklama": "45-45-90'da hipotenus=kenar*Karekoku(2)=7*Karekoku(2)"},
    {"soru": "ABC ucgeninde A:B:C = 1:2:3 ise en buyuk aci kactir?", "secenekler": ["A) 60", "B) 80", "C) 90", "D) 120"], "cevap": 2, "konu": "Ucgenler", "aciklama": "x+2x+3x=180, 6x=180, x=30. En buyuk=90"},
    {"soru": "Cesitkenar ucgenin kenarlari 5, 7, 9 ise cevresi kactir?", "secenekler": ["A) 19", "B) 21", "C) 23", "D) 25"], "cevap": 1, "konu": "Ucgenler", "aciklama": "5+7+9=21"},
    {"soru": "ABC ve DEF benzer ucgenlerde AB=4, DE=6, alan(ABC)=24 ise alan(DEF) kactir?", "secenekler": ["A) 36", "B) 48", "C) 54", "D) 72"], "cevap": 2, "konu": "Ucgenler", "aciklama": "Alan orani=(6/4)^2=9/4. 24x9/4=54"},
    {"soru": "Bir ucgenin bir dis acisi 130 derece ise bu aciya komsu olmayan iki ic acinin toplami kactir?", "secenekler": ["A) 50", "B) 100", "C) 130", "D) 180"], "cevap": 2, "konu": "Ucgenler", "aciklama": "Dis aci = komsu olmayan iki ic acinin toplami = 130"},
    {"soru": "Dik ucgende kenarlar 20 ve 21 ise hipotenus kactir?", "secenekler": ["A) 27", "B) 28", "C) 29", "D) 30"], "cevap": 2, "konu": "Ucgenler", "aciklama": "20^2+21^2=400+441=841. Karekoku(841)=29"},
    {"soru": "Ikizkenar ucgende esit kenarlar 10 cm, tepe acisi 40 ise taban acilari kacar derecedir?", "secenekler": ["A) 50", "B) 60", "C) 70", "D) 80"], "cevap": 2, "konu": "Ucgenler", "aciklama": "(180-40)/2=70"},
    {"soru": "3-4-5 ucgenine benzer ucgenin uzun kenari 15 ise en kisa kenari kactir?", "secenekler": ["A) 6", "B) 9", "C) 10", "D) 12"], "cevap": 1, "konu": "Ucgenler", "aciklama": "15/5=3. En kisa kenar=3x3=9"},
    {"soru": "Ucgenin cevresi 36 cm. Kenarlar 3:4:5 oraninda ise en uzun kenar kac cm?", "secenekler": ["A) 9", "B) 12", "C) 15", "D) 18"], "cevap": 2, "konu": "Ucgenler", "aciklama": "3k+4k+5k=36, 12k=36, k=3. En uzun=15"},
    {"soru": "Ucgenin cevresi 30 cm. Kenarlar 2:3:5 oraninda ise en uzun kenar kac cm?", "secenekler": ["A) 6", "B) 9", "C) 12", "D) 15"], "cevap": 3, "konu": "Ucgenler", "aciklama": "2k+3k+5k=30, 10k=30, k=3. En uzun=15. Ama 6+9=15 ucgen olmaz. Duzeltme: kenarlar 2:3:5 ucgen olusturamaz."},
    {"soru": "Dik ucgende kenarlar 11 ve 60 ise hipotenus kactir?", "secenekler": ["A) 59", "B) 61", "C) 63", "D) 71"], "cevap": 1, "konu": "Ucgenler", "aciklama": "11^2+60^2=121+3600=3721. Karekoku(3721)=61"},
    {"soru": "Bir ucgenin iki acisi 55 ve 65 ise bu ucgen ne tur ucgendir?", "secenekler": ["A) Dar acili", "B) Dik acili", "C) Genis acili", "D) Eskenar"], "cevap": 0, "konu": "Ucgenler", "aciklama": "Ucuncu aci=180-55-65=60. Tum acilar 90'dan kucuk: dar acili"},
    {"soru": "ABC'de A=90, AB=5, AC=12 ise BC kactir?", "secenekler": ["A) 11", "B) 12", "C) 13", "D) 14"], "cevap": 2, "konu": "Ucgenler", "aciklama": "5^2+12^2=169. BC=13"},
    {"soru": "Bir dik ucgenin alani 30 cm^2 ve bir dik kenari 5 cm ise diger dik kenar kac cm?", "secenekler": ["A) 6", "B) 10", "C) 12", "D) 15"], "cevap": 2, "konu": "Ucgenler", "aciklama": "30=(5xx)/2, x=12"},
    {"soru": "Ucgenin kenarlari 8, 15, 17 ise bu ucgen dik acili midir?", "secenekler": ["A) Evet", "B) Hayir, dar", "C) Hayir, genis", "D) Belirlenemez"], "cevap": 0, "konu": "Ucgenler", "aciklama": "8^2+15^2=64+225=289=17^2. Evet dik acili"},
    {"soru": "30-60-90 ucgeninde hipotenus 20 ise uzun kenar kactir?", "secenekler": ["A) 10", "B) 10*Karekoku(3)", "C) 15", "D) 20*Karekoku(3)"], "cevap": 1, "konu": "Ucgenler", "aciklama": "Kisa=10, uzun=10*Karekoku(3)"},
