    {"soru": "2, 4, 6, 8 verisinin degisim araligi (acikligi) kactir?", "secenekler": ["A) 2", "B) 4", "C) 6", "D) 8"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "Max-Min=8-2=6"},
    {"soru": "3, 3, 5, 7, 7 verisinin medyani kactir?", "secenekler": ["A) 3", "B) 5", "C) 6", "D) 7"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "Ortadaki: 5"},
    {"soru": "Bir sinifin not ortalamasi 70. 80 alan bir ogrenci ekleniyor. Ortalama yukselir mi?", "secenekler": ["A) Duser", "B) Degismez", "C) Yukselir", "D) Bilinemez"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "80>70 oldugu icin ortalama yukselir"},
    {"soru": "4, 6, 8, 10, 12 verisinin ortalamasi kactir?", "secenekler": ["A) 6", "B) 7", "C) 8", "D) 9"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "40/5=8"},
    {"soru": "10 ogrencinin sinav ortalamasi 65. Toplam puan kactir?", "secenekler": ["A) 550", "B) 600", "C) 650", "D) 700"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "10x65=650"},
    {"soru": "2, 5, 5, 8, 10 verisinin ortancasi kactir?", "secenekler": ["A) 2", "B) 5", "C) 8", "D) 10"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "Ortadaki: 5"},
    {"soru": "Bir ogrencinin 4 sinav notu: 60, 75, 80, 85. 5. sinavdan kac alirsa ortalamasi 75 olur?", "secenekler": ["A) 70", "B) 75", "C) 80", "D) 85"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "(300+x)/5=75, 300+x=375, x=75"},
    {"soru": "1, 2, 2, 3, 3, 3, 4, 4, 4, 4 verisinin modu kactir?", "secenekler": ["A) 1", "B) 2", "C) 3", "D) 4"], "cevap": 3, "konu": "Veri Analizi", "aciklama": "4 en cok tekrar eden (4 kez)"},
    {"soru": "5, 10, 15, 20, 25 verisinin degisim araligi kactir?", "secenekler": ["A) 5", "B) 10", "C) 15", "D) 20"], "cevap": 3, "konu": "Veri Analizi", "aciklama": "25-5=20"},
    {"soru": "8 sayinin toplami 96 ise ortalama kactir?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 14"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "96/8=12"},
    {"soru": "3, 5, 7, x, 13 verisinin ortalamasi 8 ise x kactir?", "secenekler": ["A) 10", "B) 11", "C) 12", "D) 14"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "(28+x)/5=8, 28+x=40, x=12"},
    {"soru": "Bir histogramda en yuksek sutunun gosterdigi nedir?", "secenekler": ["A) Ortalama", "B) Medyan", "C) Mod sinifi", "D) Degisim araligi"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "En yuksek sutun en cok tekrar eden sinifi (mod sinifi) gosterir"},
    {"soru": "2, 2, 4, 6, 6, 8, 8, 8 verisinin modu kactir?", "secenekler": ["A) 2", "B) 4", "C) 6", "D) 8"], "cevap": 3, "konu": "Veri Analizi", "aciklama": "8 en cok tekrar eden (3 kez)"},
    {"soru": "10, 20, 30 verisinin ortalamasi ile medyani farki kactir?", "secenekler": ["A) 0", "B) 5", "C) 10", "D) 20"], "cevap": 0, "konu": "Veri Analizi", "aciklama": "Ortalama=20, Medyan=20. Fark=0"},
    {"soru": "Bir sinifta 5 kiz ortalamasi 80, 5 erkek ortalamasi 70 ise sinif ortalamasi kactir?", "secenekler": ["A) 72", "B) 74", "C) 75", "D) 78"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "(5x80+5x70)/10=750/10=75"},
    {"soru": "1, 3, 5 verisinin standart sapmasi icin once varyans bulalim. Varyans kactir?", "secenekler": ["A) 2/3", "B) 4/3", "C) 8/3", "D) 16/3"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "Ortalama=3. Varyans=((1-3)^2+(3-3)^2+(5-3)^2)/3=(4+0+4)/3=8/3"},
    {"soru": "Bir veri setinin tum degerlerine 5 eklenirse ortalama nasil degisir?", "secenekler": ["A) 5 artar", "B) 5 azalir", "C) Degismez", "D) 2 katina cikar"], "cevap": 0, "konu": "Veri Analizi", "aciklama": "Tum degerlere sabit eklenirse ortalama da o kadar artar"},
    {"soru": "4, 4, 4, 4, 4 verisinin standart sapmasi kactir?", "secenekler": ["A) 0", "B) 1", "C) 2", "D) 4"], "cevap": 0, "konu": "Veri Analizi", "aciklama": "Tum degerler ayni. Standart sapma=0"},
    {"soru": "Medyan bulunurken veriler nasil siralanir?", "secenekler": ["A) Buyukten kucuge", "B) Kucukten buyuge", "C) Ikisi de olur", "D) Siralamaya gerek yok"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "Medyan icin kucukten buyuge veya buyukten kucuge siralanir"},
    {"soru": "2, 4, 6, 8, 10, 12 verisinin medyani kactir?", "secenekler": ["A) 6", "B) 7", "C) 8", "D) 9"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "Cift elemanli: (6+8)/2=7"},
    {"soru": "Bir veri setinin tum degerleri 3 ile carpilirsa standart sapma nasil degisir?", "secenekler": ["A) 3 katina cikar", "B) 9 katina cikar", "C) Degismez", "D) 3'e bolunur"], "cevap": 0, "konu": "Veri Analizi", "aciklama": "Standart sapma da 3 katina cikar"},
    {"soru": "5, 10, 15, 20, 25, 30 verisinin ortalamasi kactir?", "secenekler": ["A) 15.5", "B) 17.5", "C) 20", "D) 22.5"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "105/6=17.5"},
    {"soru": "1, 1, 2, 2, 3, 3 verisinin modu kactir?", "secenekler": ["A) 1", "B) 2", "C) 3", "D) Mod yok (cok modlu)"], "cevap": 3, "konu": "Veri Analizi", "aciklama": "1, 2, 3 hepsi 2'ser kez. Cok modlu veri."},
    {"soru": "Ortalamasi 50 olan 10 sayinin toplami kactir?", "secenekler": ["A) 400", "B) 450", "C) 500", "D) 550"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "50x10=500"},
    {"soru": "2, 6, 10, 14, 18 verisinin degisim araligi kactir?", "secenekler": ["A) 4", "B) 8", "C) 12", "D) 16"], "cevap": 3, "konu": "Veri Analizi", "aciklama": "18-2=16"},
    {"soru": "20 ogrencinin ortalamasi 72. Bir ogrenci 92 alarak eklenirse yeni ortalama yaklasik kactir?", "secenekler": ["A) 72", "B) 72.5", "C) 73", "D) 74"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "(1440+92)/21=1532/21~72.95, yaklasik 73"},
    {"soru": "Bir ogrenci 5 sinavdan 60,70,80,90,100 aldi. Standart sapmasi icin varyans kactir?", "secenekler": ["A) 100", "B) 150", "C) 200", "D) 250"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "Ort=80. V=((20)^2+(10)^2+0+(10)^2+(20)^2)/5=(400+100+0+100+400)/5=200"},
    {"soru": "Mod, medyan ve ortalamasi ayni olan simetrik dagilimda 3 degerin esitligi ne anlama gelir?", "secenekler": ["A) Sola carpik", "B) Saga carpik", "C) Simetrik", "D) Bimodal"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "Uc olcu esitse dagilim simetriktir"},
    {"soru": "10, 12, 14, 16, 18 verisinin ortalamasi kactir?", "secenekler": ["A) 12", "B) 13", "C) 14", "D) 15"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "70/5=14"},
    {"soru": "3, 7, 7, 10, 13 verisinin ortalama ile medyan farki kactir?", "secenekler": ["A) 0", "B) 1", "C) 2", "D) 3"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "Ortalama=40/5=8, Medyan=7. Fark=1"},
    {"soru": "Bir veri setinden en buyuk deger cikarilirsa kesinlikle ne degisir?", "secenekler": ["A) Yalniz mod", "B) Yalniz medyan", "C) Degisim araligi", "D) Hicbiri"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "En buyuk deger cikarilinca degisim araligi mutlaka degisir"},
    {"soru": "6 sayinin toplami 42. En kucuk 3'u cikarilinca kalan 3 sayinin ortalamasi 10 ise cikarilan 3 sayinin ortalamasi kactir?", "secenekler": ["A) 2", "B) 3", "C) 4", "D) 5"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "Kalan toplam=30. Cikarilan toplam=42-30=12. Ortalama=12/3=4"},
    {"soru": "Bir pasta grafikte %25 dilim kac derecelik acidir?", "secenekler": ["A) 25", "B) 45", "C) 90", "D) 120"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "360x0.25=90 derece"},
    {"soru": "Agirlikli ortalamada: Matematik(katsayi 3, not 80), Turkce(katsayi 2, not 70). Agirlikli ortalama kactir?", "secenekler": ["A) 74", "B) 75", "C) 76", "D) 78"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "(3x80+2x70)/(3+2)=(240+140)/5=380/5=76"},
    {"soru": "Bir sinifta notlar: 50(3 kisi), 70(5 kisi), 90(2 kisi). Ortalama kactir?", "secenekler": ["A) 66", "B) 68", "C) 70", "D) 72"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "(150+350+180)/10=680/10=68"},
    {"soru": "Ceyrekler arasi aciklik (IQR) nasil hesaplanir?", "secenekler": ["A) Q3-Q1", "B) Q2-Q1", "C) Q3-Q2", "D) Max-Min"], "cevap": 0, "konu": "Veri Analizi", "aciklama": "IQR = Q3 - Q1"},
    {"soru": "5, 8, 8, 10, 12, 15 verisinin alt ceyrek degeri (Q1) kactir?", "secenekler": ["A) 5", "B) 8", "C) 10", "D) 12"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "Alt yari: 5,8,8. Q1=8"},
    {"soru": "Bir kutu grafikte kutunun ici neyi temsil eder?", "secenekler": ["A) Tum veriyi", "B) IQR araligini", "C) Ortalama araligini", "D) Standart sapmayi"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "Kutu IQR'yi (Q1-Q3 arasi) temsil eder"},
    {"soru": "3, 3, 4, 5, 5, 5, 6, 7 verisinin modu ve medyani sirasiyla nedir?", "secenekler": ["A) 3 ve 5", "B) 5 ve 5", "C) 5 ve 4.5", "D) 3 ve 4.5"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "Mod=5 (3 kez). Medyan=(5+5)/2=5"},
    {"soru": "Bir veri setinin ortalamasi 40, standart sapmasi 5 ise verilerin %68'i hangi aralikta?", "secenekler": ["A) 30-50", "B) 35-45", "C) 25-55", "D) 40-45"], "cevap": 1, "konu": "Veri Analizi", "aciklama": "Normal dagilimda %68 ort+-1ss: 35-45"},
    {"soru": "2, 4, 4, 5, 7, 8 verisinin ortalamasi kactir?", "secenekler": ["A) 4", "B) 4.5", "C) 5", "D) 5.5"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "30/6=5"},
    {"soru": "Bir sinifin Matematik ortalamasi 75, Turkce ortalamasi 85 ise iki dersin birlesik ortalamasi hakkinda ne soylenir?", "secenekler": ["A) 80", "B) 75-85 arasi", "C) Ogrenci sayisi bilinmeden bilinemez", "D) 160"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "Birlesik ortalama icin her iki dersteki ogrenci sayisi bilinmelidir"},
    {"soru": "10, 20, 30, 40, 50 verisinin varyans degeri kactir?", "secenekler": ["A) 100", "B) 150", "C) 200", "D) 250"], "cevap": 2, "konu": "Veri Analizi", "aciklama": "Ort=30. V=((20)^2+(10)^2+0+(10)^2+(20)^2)/5=1000/5=200"},
    # ===== Eslik ve Benzerlik (50 soru) =====
    {"soru": "Iki ucgenin eslik kosullarindan hangisi YANLISTIR?", "secenekler": ["A) KKK", "B) KAK", "C) AKA", "D) AAA"], "cevap": 3, "konu": "Eslik ve Benzerlik", "aciklama": "AAA ucgen esligini garanti etmez, benzerlik kosulu olabilir ama eslik icin yeterli degildir."},
    {"soru": "ABC ucgeninde AB=5, BC=7, AC=8. DEF ucgeninde DE=5, EF=7, DF=8. Hangi eslik kosulu saglanir?", "secenekler": ["A) KAK", "B) KKK", "C) AKA", "D) Eslik yok"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Uc kenar esit oldugu icin KKK (Kenar-Kenar-Kenar) eslik kosulu saglanir."},
    {"soru": "ABC ve DEF ucgenleri esit ise AB=6 cm, DE kac cm dir?", "secenekler": ["A) 3", "B) 6", "C) 12", "D) Bilinemez"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Esit ucgenlerde karsilikli kenarlar esittir. AB=DE=6 cm."},
    {"soru": "Bir ucgenin iki kenari 4 cm ve 6 cm, aralarindaki aci 60 derece. Baska bir ucgenin iki kenari 4 cm ve 6 cm, aralarindaki aci 60 derece. Hangi eslik kosulu?", "secenekler": ["A) KKK", "B) KAK", "C) AKA", "D) AKK"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Iki kenar ve aralarindaki aci esit -> KAK (Kenar-Aci-Kenar) eslik kosulu."},
    {"soru": "ABC ucgeninde A=50, B=70 ise C kac derecedir?", "secenekler": ["A) 50", "B) 60", "C) 70", "D) 80"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "A+B+C=180. 50+70+C=180. C=60 derece."},
    {"soru": "Iki ucgen benzer ise benzerlik orani 3/5 dir. Birinci ucgenin cevresi 24 cm ise ikinci ucgenin cevresi kac cm?", "secenekler": ["A) 32", "B) 36", "C) 40", "D) 48"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "Cevreler de ayni orandadir. 24/(3/5)=24x5/3=40 cm."},
    {"soru": "ABC ~ DEF ve benzerlik orani 2/3 ise alan orani kactir?", "secenekler": ["A) 2/3", "B) 4/9", "C) 8/27", "D) 2/9"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Benzer ucgenlerde alan orani, benzerlik oraninin karesidir. (2/3)^2=4/9."},
    {"soru": "ABC ucgeninde DE//BC, AD=3, DB=6, AE=4 ise EC kac cm?", "secenekler": ["A) 6", "B) 8", "C) 10", "D) 12"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Temel orantillik teoremi: AD/DB=AE/EC. 3/6=4/EC. EC=8 cm."},
    {"soru": "Benzer iki ucgenin kenarlari 6 cm ve 9 cm ise benzerlik orani kactir?", "secenekler": ["A) 1/2", "B) 2/3", "C) 3/4", "D) 1/3"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Benzerlik orani = 6/9 = 2/3."},
    {"soru": "ABC ~ DEF, AB=8, DE=12, BC=6 ise EF kac cm?", "secenekler": ["A) 4", "B) 9", "C) 10", "D) 12"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "AB/DE=BC/EF. 8/12=6/EF. EF=9 cm."},
    {"soru": "Benzer iki ucgenin alanlari 16 ve 36 cm^2 ise benzerlik orani kactir?", "secenekler": ["A) 4/9", "B) 2/3", "C) 16/36", "D) 8/18"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Alan orani=16/36=4/9. Benzerlik orani=sqrt(4/9)=2/3."},
    {"soru": "ABC ucgeninde DE//BC, AD=4 cm, DB=8 cm ise ADE ve ABC nin alan orani kactir?", "secenekler": ["A) 1/4", "B) 1/9", "C) 1/3", "D) 4/9"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "AD/AB=4/12=1/3. Alan orani=(1/3)^2=1/9."},
    {"soru": "Iki benzer ucgenin cevre orani 5:3 ise alan orani kactir?", "secenekler": ["A) 5:3", "B) 10:6", "C) 25:9", "D) 15:9"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "Alan orani = benzerlik oraninin karesi = 25:9."},
    {"soru": "ABC ucgeninde D, AB uzerinde, E, AC uzerinde. DE//BC, AD=5, AB=15, DE=4 ise BC kac cm?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 16"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "AD/AB=DE/BC. 5/15=4/BC. BC=12 cm."},
    {"soru": "Bir ucgenin kenarlari 3, 4, 5 cm. Benzer ucgenin en uzun kenari 15 cm ise en kisa kenari kac cm?", "secenekler": ["A) 6", "B) 9", "C) 10", "D) 12"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Benzerlik orani=15/5=3. En kisa kenar=3x3=9 cm."},
    {"soru": "ABC ve DEF ucgenlerinde A=D=40, B=E=60. Bu ucgenler icin ne soylenir?", "secenekler": ["A) Esittir", "B) Benzerdir", "C) Ne esit ne benzer", "D) Bilinemez"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "AA (Aci-Aci) benzerlik kosulu saglanir. Iki aci esit ise ucgenler benzerdir."},
    {"soru": "Benzer iki ucgenin karsilikli yukseklikleri 6 cm ve 10 cm. Kucuk ucgenin alani 27 cm^2 ise buyuk ucgenin alani kac cm^2?", "secenekler": ["A) 45", "B) 60", "C) 75", "D) 90"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "Benzerlik orani=6/10=3/5. Alan orani=9/25. 27/(9/25)=75 cm^2. Duzeltme: 27x25/9=75 cm^2."},
    {"soru": "KAK eslik kosulunda 'A' neyi ifade eder?", "secenekler": ["A) Alan", "B) Aci", "C) Ayna", "D) Aralik"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "KAK: Kenar-Aci-Kenar. A, iki kenar arasindaki aciyi ifade eder."},
    {"soru": "ABC ucgeninde AB=DE, AC=DF, A=D ise hangi eslik kosulu saglanir?", "secenekler": ["A) KKK", "B) KAK", "C) AKA", "D) AAK"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Iki kenar ve aralarindaki aci esit: KAK eslik kosulu."},
    {"soru": "Iki benzer ucgenin hacim orani 8:27 ise benzerlik orani kactir?", "secenekler": ["A) 2:3", "B) 4:9", "C) 8:27", "D) 2:9"], "cevap": 0, "konu": "Eslik ve Benzerlik", "aciklama": "Hacim orani = benzerlik oraninin kupu. Kup kok(8/27)=2/3."},
    {"soru": "ABC ~ DEF, AB/DE=3/4, ABC alani 36 cm^2 ise DEF alani kac cm^2?", "secenekler": ["A) 48", "B) 54", "C) 64", "D) 72"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "Alan orani=(3/4)^2=9/16. 36/x=9/16. x=64 cm^2."},
    {"soru": "ABC ucgeninde DE//BC, AD=2, DB=4, BC=9 ise DE kac cm?", "secenekler": ["A) 2", "B) 3", "C) 4", "D) 6"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "AD/AB=DE/BC. 2/6=DE/9. DE=3 cm."},
    {"soru": "Esit iki ucgenin cevreleri icin ne soylenir?", "secenekler": ["A) Farklidir", "B) Esittir", "C) Orantilidir", "D) Bilinemez"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Esit ucgenlerin tum karsilikli kenarlari esittir, dolayisiyla cevreleri de esittir."},
    {"soru": "ABC ucgeninde D, AB uzerinde, E, AC uzerinde. AD/DB=AE/EC ise ne soylenir?", "secenekler": ["A) DE=BC", "B) DE//BC", "C) DE>BC", "D) DE perp BC"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Temel orantillik teoreminin tersi: AD/DB=AE/EC ise DE//BC dir."},
    {"soru": "Benzerlik orani 1:1 olan iki ucgen icin ne soylenir?", "secenekler": ["A) Benzerdir ama esit degildir", "B) Esittir", "C) Sadece acilari esittir", "D) Bilinemez"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Benzerlik orani 1:1 ise tum kenarlar esittir, yani ucgenler esittir."},
    {"soru": "ABC ~ DEF, AB=10, BC=8, CA=6, DE=5 ise EF+FD kac cm?", "secenekler": ["A) 5", "B) 7", "C) 8", "D) 10"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Oran=5/10=1/2. EF=4, FD=3. EF+FD=7 cm."},
    {"soru": "Bir fotografin genisligi 4 cm, yuksekligi 6 cm. Genisligi 10 cm olacak sekilde buyutulurse yuksekligi kac cm olur?", "secenekler": ["A) 12", "B) 15", "C) 18", "D) 20"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "4/10=6/y. y=15 cm."},
    {"soru": "ABC ucgeninde DE//BC, AE=5, EC=10, AD=3 ise DB kac cm?", "secenekler": ["A) 4", "B) 5", "C) 6", "D) 8"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "AD/DB=AE/EC. 3/DB=5/10. DB=6 cm."},
    {"soru": "Iki ucgenin tum acilari esit ise bu ucgenler kesinlikle nedir?", "secenekler": ["A) Esit", "B) Benzer", "C) Dik", "D) Ikizkenar"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Tum acilari esit olan ucgenler benzerdir (AAA benzerlik)."},
    {"soru": "ABC ~ DEF, benzerlik orani k=2. ABC cevresi 18 cm ise DEF cevresi kac cm?", "secenekler": ["A) 6", "B) 9", "C) 18", "D) 36"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "ABC/DEF=2. DEF cevresi=18/2=9 cm."},
    {"soru": "ABC ucgeninde A=90, AB=6, AC=8, BC=10. DEF~ABC, DE=3. EF kac cm?", "secenekler": ["A) 4", "B) 5", "C) 6", "D) 8"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Oran=3/6=1/2. EF=BC/2=10/2=5 cm."},
    {"soru": "Benzer iki ucgenin karsilikli kenarlari 4 ve 6 cm. Kucuk ucgenin cevresi 20 cm ise buyuk ucgenin cevresi kac cm?", "secenekler": ["A) 25", "B) 30", "C) 35", "D) 40"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Oran=4/6=2/3. 20/x=2/3. x=30 cm."},
    {"soru": "ABC ucgeninde D, BC nin orta noktasi. AD medyan. ABD ve ACD ucgenleri icin ne soylenir?", "secenekler": ["A) Esittir", "B) Alanlari esittir", "C) Benzerdir", "D) Iliski yoktur"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Medyan ucgeni esit alanli iki ucgene boler. BD=DC, yukseklikleri ayni."},
    {"soru": "3 cm, 4 cm, 5 cm kenarli ucgenle 6 cm, 8 cm, 10 cm kenarli ucgen benzer mi?", "secenekler": ["A) Hayir", "B) Evet, oran 1:2", "C) Evet, oran 2:3", "D) Evet, oran 1:3"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "3/6=4/8=5/10=1/2. Tum kenar oranlari esit, benzerlik orani 1:2."},
    {"soru": "ABC ~ DEF, alan orani 1:4 ise cevre orani kactir?", "secenekler": ["A) 1:2", "B) 1:4", "C) 1:8", "D) 1:16"], "cevap": 0, "konu": "Eslik ve Benzerlik", "aciklama": "Alan orani=k^2=1/4. k=1/2. Cevre orani=1:2."},
    {"soru": "ABC ucgeninde DE//BC, AD=x, DB=x+4, AE=3, EC=6. x kactir?", "secenekler": ["A) 1", "B) 2", "C) 3", "D) 4"], "cevap": 3, "konu": "Eslik ve Benzerlik", "aciklama": "AD/DB=AE/EC. x/(x+4)=3/6=1/2. 2x=x+4. x=4."},
    {"soru": "Ikizkenar ucgende taban 8 cm, esit kenarlar 5 cm. Buna benzer ucgenin tabani 16 cm ise esit kenari kac cm?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 15"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Oran=16/8=2. Esit kenar=5x2=10 cm."},
    {"soru": "ABC ucgeninde A acisinin aciortsyi AD. BD=3, DC=5, AB=6 ise AC kac cm?", "secenekler": ["A) 8", "B) 10", "C) 12", "D) 15"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Aci ortay teoremi: AB/AC=BD/DC. 6/AC=3/5. AC=10 cm."},
    {"soru": "ABC ucgeninde yukseklik h=12 cm, taban a=10 cm. Benzer ucgende karsilikli taban 15 cm ise yukseklik kac cm?", "secenekler": ["A) 14", "B) 16", "C) 18", "D) 20"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "Oran=15/10=3/2. Yukseklik=12x3/2=18 cm."},
    {"soru": "Bir ucgenin acilari 40, 60, 80 derece. Baska bir ucgenin acilari 40, 80, x derece ise x kac?", "secenekler": ["A) 40", "B) 50", "C) 60", "D) 80"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "40+80+x=180. x=60 derece. Iki ucgen benzerdir (AA kosulu)."},
    {"soru": "KKK eslik kosulunda en az kac olcu bilinmelidir?", "secenekler": ["A) 2", "B) 3", "C) 4", "D) 6"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "KKK: Uc kenar bilinmelidir. 3 olcu yeterlidir."},
    {"soru": "ABC ~ DEF, AB=12, DE=8. ABC alani 54 cm^2 ise DEF alani kac cm^2?", "secenekler": ["A) 16", "B) 24", "C) 36", "D) 48"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Oran=8/12=2/3. Alan orani=4/9. DEF=54x4/9=24 cm^2."},
    {"soru": "Dikdortgenin kisa kenari 3, uzun kenari 4. Benzer dikdortgenin uzun kenari 12 ise kisa kenari kac?", "secenekler": ["A) 6", "B) 8", "C) 9", "D) 10"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "Oran=12/4=3. Kisa kenar=3x3=9."},
    {"soru": "ABC ucgeninde DE//BC, AD=6, AB=18, AE=5 ise AC kac cm?", "secenekler": ["A) 10", "B) 12", "C) 15", "D) 18"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "AD/AB=AE/AC. 6/18=5/AC. AC=15 cm."},
    {"soru": "Benzer iki ucgenin cevre orani 3:7 ise alan orani kactir?", "secenekler": ["A) 3:7", "B) 6:14", "C) 9:49", "D) 27:343"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "Alan orani = cevre oraninin karesi = 9:49."},
    {"soru": "ABC ucgeninde D ve E sirasiyla AB ve AC uzerinde. BD=4, DA=2, CE=6, EA=3. DE//BC midir?", "secenekler": ["A) Evet", "B) Hayir", "C) Bilinemez", "D) Bazen"], "cevap": 0, "konu": "Eslik ve Benzerlik", "aciklama": "DA/DB=2/4=1/2. EA/EC=3/6=1/2. Oranlar esit, DE//BC."},
    {"soru": "AKA eslik kosulunda hangi elemanlar esit olmalidir?", "secenekler": ["A) 3 aci", "B) 2 aci, 1 kenar (acilarin arasi)", "C) 2 kenar, 1 aci", "D) 1 aci, 2 kenar (herhangi)"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "AKA: Aci-Kenar-Aci. Iki aci ve aralarindaki kenar esit olmalidir."},
    {"soru": "Bir haritada 2 cm = 5 km. Haritada 7 cm olan mesafe gercekte kac km?", "secenekler": ["A) 14", "B) 15", "C) 17.5", "D) 20"], "cevap": 2, "konu": "Eslik ve Benzerlik", "aciklama": "2/5=7/x. x=17.5 km."},
    {"soru": "ABC ucgeninde AB=10, BC=12, CA=14. DEF ucgeninde DE=5, EF=6, FD=7. Benzerlik orani kactir?", "secenekler": ["A) 1:3", "B) 1:2", "C) 2:3", "D) 3:4"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "5/10=6/12=7/14=1/2. Benzerlik orani 1:2."},
    {"soru": "Benzer iki ucgenin karsilikli kenar orta cizgileri 4 ve 6 cm ise benzerlik orani kactir?", "secenekler": ["A) 1:2", "B) 2:3", "C) 3:4", "D) 4:5"], "cevap": 1, "konu": "Eslik ve Benzerlik", "aciklama": "Kenar orta cizgiler de benzerlik oranindadir. 4/6=2/3."},
    # ===== Geometrik Cisimler (50 soru) =====
    {"soru": "Taban kenari 5 cm, yuksekligi 8 cm olan kare prizmanin hacmi kac cm^3?", "secenekler": ["A) 100", "B) 150", "C) 200", "D) 250"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Hacim=Taban alani x yukseklik = 5^2 x 8 = 25 x 8 = 200 cm^3."},
    {"soru": "Yaricapi 3 cm, yuksekligi 10 cm olan silindirin hacmi kac cm^3? (pi=3)", "secenekler": ["A) 90", "B) 180", "C) 270", "D) 360"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Hacim=pi x r^2 x h = 3 x 9 x 10 = 270 cm^3."},
    {"soru": "Bir kupun bir yuzunun alani 25 cm^2 ise hacmi kac cm^3?", "secenekler": ["A) 75", "B) 100", "C) 125", "D) 150"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Kenar=5 cm. Hacim=5^3=125 cm^3."},
    {"soru": "Yaricapi 6 cm olan kurenin hacmi kac cm^3? (pi=3)", "secenekler": ["A) 648", "B) 756", "C) 864", "D) 972"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Hacim=4/3 x pi x r^3 = 4/3 x 3 x 216 = 4 x 216 = 864 cm^3."},
    {"soru": "Taban yaricapi 4 cm, yuksekligi 9 cm olan koninin hacmi kac cm^3? (pi=3)", "secenekler": ["A) 108", "B) 144", "C) 216", "D) 432"], "cevap": 1, "konu": "Geometrik Cisimler", "aciklama": "Hacim=1/3 x pi x r^2 x h = 1/3 x 3 x 16 x 9 = 144 cm^3."},
    {"soru": "Bir dikdortgenler prizmasinin boyutlari 3, 4, 5 cm. Hacmi kac cm^3?", "secenekler": ["A) 30", "B) 45", "C) 60", "D) 75"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Hacim=3x4x5=60 cm^3."},
    {"soru": "Bir kupun hacmi 64 cm^3 ise toplam yuzey alani kac cm^2?", "secenekler": ["A) 48", "B) 64", "C) 96", "D) 128"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Kenar=4 cm. Yuzey alani=6x4^2=6x16=96 cm^2."},
    {"soru": "Yaricapi 5 cm olan kurenin yuzey alani kac cm^2? (pi=3)", "secenekler": ["A) 200", "B) 250", "C) 300", "D) 350"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Yuzey alani=4 x pi x r^2 = 4 x 3 x 25 = 300 cm^2."},
    {"soru": "Taban kenarlari 6 ve 8 cm, yuksekligi 10 cm olan dikdortgenler prizmasinin hacmi kac cm^3?", "secenekler": ["A) 240", "B) 360", "C) 480", "D) 600"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Hacim=6x8x10=480 cm^3."},
    {"soru": "Bir silindirin taban alani 50 cm^2, yuksekligi 7 cm ise hacmi kac cm^3?", "secenekler": ["A) 250", "B) 300", "C) 350", "D) 400"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Hacim=Taban alani x h = 50 x 7 = 350 cm^3."},
    {"soru": "Bir koninin hacmi 120 cm^3, taban alani 40 cm^2 ise yuksekligi kac cm?", "secenekler": ["A) 3", "B) 6", "C) 9", "D) 12"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "V=1/3 x A x h. 120=1/3 x 40 x h. h=9 cm."},
    {"soru": "Dikdortgenler prizmasinin boyutlari 2, 3, 6 cm. Toplam yuzey alani kac cm^2?", "secenekler": ["A) 36", "B) 48", "C) 60", "D) 72"], "cevap": 3, "konu": "Geometrik Cisimler", "aciklama": "Y.A.=2(2x3+2x6+3x6)=2(6+12+18)=2x36=72 cm^2."},
    {"soru": "Bir kupun tum kenarlarinin toplami 60 cm ise hacmi kac cm^3?", "secenekler": ["A) 25", "B) 64", "C) 100", "D) 125"], "cevap": 3, "konu": "Geometrik Cisimler", "aciklama": "Kup 12 kenara sahip. 12a=60, a=5 cm. Hacim=125 cm^3."},
    {"soru": "Yaricapi 3 cm, yuksekligi 5 cm olan silindirin yanal yuzey alani kac cm^2? (pi=3)", "secenekler": ["A) 45", "B) 60", "C) 75", "D) 90"], "cevap": 3, "konu": "Geometrik Cisimler", "aciklama": "Yanal alan=2 x pi x r x h = 2 x 3 x 3 x 5 = 90 cm^2."},
    {"soru": "Silindirin hacmi 300 cm^3, yaricapi 5 cm ise yuksekligi kac cm? (pi=3)", "secenekler": ["A) 2", "B) 3", "C) 4", "D) 5"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "V=pi x r^2 x h. 300=3 x 25 x h. h=4 cm."},
    {"soru": "Taban kenari 6 cm olan duzgun dort yuzlunun (tetrahedron) kac yuzeysi vardir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 1, "konu": "Geometrik Cisimler", "aciklama": "Duzgun dort yuzlunun 4 yuzeysi vardir."},
    {"soru": "Bir dikdortgenler prizmasinin hacmi 180 cm^3, taban alani 30 cm^2 ise yuksekligi kac cm?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 3, "konu": "Geometrik Cisimler", "aciklama": "V=A x h. 180=30 x h. h=6 cm."},
    {"soru": "Yaricapi 2 katina cikan kurenin hacmi kac katina cikar?", "secenekler": ["A) 2", "B) 4", "C) 6", "D) 8"], "cevap": 3, "konu": "Geometrik Cisimler", "aciklama": "Hacim r^3 ile orantili. (2r)^3=8r^3. 8 katina cikar."},
    {"soru": "Taban yaricapi 3 cm, yuksekligi 4 cm olan koninin ana dogrusu (anametre) kac cm?", "secenekler": ["A) 4", "B) 5", "C) 6", "D) 7"], "cevap": 1, "konu": "Geometrik Cisimler", "aciklama": "Ana dogru=sqrt(r^2+h^2)=sqrt(9+16)=sqrt(25)=5 cm."},
    {"soru": "Bir kupun kosegen uzunlugu 5*sqrt(3) cm ise kenari kac cm?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Cisim kosegeni=a*sqrt(3). a*sqrt(3)=5*sqrt(3). a=5 cm."},
    {"soru": "Yaricapi 7 cm olan kurenin hacmi kac cm^3? (pi=22/7)", "secenekler": ["A) 1078", "B) 1437", "C) 1521", "D) 1616"], "cevap": 1, "konu": "Geometrik Cisimler", "aciklama": "V=4/3 x 22/7 x 7^3 = 4/3 x 22 x 49 = 4312/3 = 1437.3 ~ 1437 cm^3."},
    {"soru": "Taban kenari 10 cm, yuksekligi 12 cm olan ucgen prizmanin hacmi kac cm^3? (Taban eskenar ucgen, alan=25*sqrt(3))", "secenekler": ["A) 300*sqrt(3)", "B) 250*sqrt(3)", "C) 200*sqrt(3)", "D) 150*sqrt(3)"], "cevap": 0, "konu": "Geometrik Cisimler", "aciklama": "Hacim=Taban alani x h = 25*sqrt(3) x 12 = 300*sqrt(3) cm^3."},
    {"soru": "Bir kupun yuzey alani 150 cm^2 ise kenar uzunlugu kac cm?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "6a^2=150. a^2=25. a=5 cm."},
    {"soru": "Silindirin yaricapi 3 katina cikarsa hacmi kac katina cikar?", "secenekler": ["A) 3", "B) 6", "C) 9", "D) 27"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Hacim r^2 ile orantili. (3r)^2=9r^2. 9 katina cikar."},
    {"soru": "Bir prizmanin taban alani 24 cm^2, hacmi 192 cm^3 ise yuksekligi kac cm?", "secenekler": ["A) 6", "B) 7", "C) 8", "D) 9"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "h=V/A=192/24=8 cm."},
    {"soru": "Yaricapi 4 cm olan yarim kurenin hacmi kac cm^3? (pi=3)", "secenekler": ["A) 64", "B) 96", "C) 128", "D) 192"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Yarim kure hacmi=2/3 x pi x r^3 = 2/3 x 3 x 64 = 128 cm^3."},
    {"soru": "Bir koninin hacmi 100 cm^3. Ayni taban ve yukseklige sahip silindirin hacmi kac cm^3?", "secenekler": ["A) 200", "B) 300", "C) 400", "D) 500"], "cevap": 1, "konu": "Geometrik Cisimler", "aciklama": "Koni hacmi=1/3 x silindir hacmi. Silindir=3x100=300 cm^3."},
    {"soru": "Boyutlari 4, 5, 6 cm olan dikdortgenler prizmasinin uzay kosegen uzunlugu kac cm?", "secenekler": ["A) sqrt(57)", "B) sqrt(67)", "C) sqrt(77)", "D) sqrt(87)"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Uzay kosegen=sqrt(4^2+5^2+6^2)=sqrt(16+25+36)=sqrt(77) cm."},
    {"soru": "Bir kupun hacmi 8 katina cikarsa kenar uzunlugu kac katina cikar?", "secenekler": ["A) 2", "B) 4", "C) 8", "D) 16"], "cevap": 0, "konu": "Geometrik Cisimler", "aciklama": "V=a^3. 8a^3=(2a)^3. Kenar 2 katina cikar."},
    {"soru": "Taban yaricapi 6 cm, yuksekligi 8 cm olan koninin yanal yuzey alani kac cm^2? (pi=3, ana dogru=10)", "secenekler": ["A) 120", "B) 150", "C) 180", "D) 210"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Yanal alan=pi x r x l = 3 x 6 x 10 = 180 cm^2."},
    {"soru": "Bir silindirin toplam yuzey alani icin hangi formul kullanilir?", "secenekler": ["A) 2*pi*r*h", "B) pi*r^2*h", "C) 2*pi*r*(r+h)", "D) 2*pi*r^2"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Toplam yuzey=2 taban + yanal = 2*pi*r^2 + 2*pi*r*h = 2*pi*r*(r+h)."},
    {"soru": "Kare prizmanin taban kenari 4 cm, hacmi 112 cm^3 ise yuksekligi kac cm?", "secenekler": ["A) 5", "B) 6", "C) 7", "D) 8"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "V=a^2 x h. 112=16 x h. h=7 cm."},
    {"soru": "Bir kurenin yaricapi 3 katina cikarsa yuzey alani kac katina cikar?", "secenekler": ["A) 3", "B) 6", "C) 9", "D) 27"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Yuzey alani r^2 ile orantili. (3r)^2=9r^2. 9 katina cikar."},
    {"soru": "Dikdortgenler prizmasinin boyutlari 2, 3, 4 cm. Yuz kosegenleri toplami kactir?", "secenekler": ["A) sqrt(13)+sqrt(20)+sqrt(25)", "B) sqrt(5)+sqrt(8)+sqrt(13)", "C) 3 farkli yuz kosegeni var", "D) sqrt(13)+sqrt(20)+sqrt(25) ve her birinden 4"], "cevap": 0, "konu": "Geometrik Cisimler", "aciklama": "Yuz kosegenleri: sqrt(4+9)=sqrt(13), sqrt(4+16)=sqrt(20), sqrt(9+16)=sqrt(25)=5."},
    {"soru": "Bir silindir su ile dolu. Yaricapi 5 cm, yuksekligi 20 cm. Su hacmi kac cm^3? (pi=3)", "secenekler": ["A) 1200", "B) 1350", "C) 1500", "D) 1650"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "V=pi x r^2 x h = 3 x 25 x 20 = 1500 cm^3."},
    {"soru": "Bir kupun icine yerlestirilebilecek en buyuk kurenin yaricapi, kup kenari 10 cm ise kac cm?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Kure capi = kup kenari. r = 10/2 = 5 cm."},
    {"soru": "Taban kenari 8 cm olan kup ile ayni hacme sahip silindirin yaricapi 4 cm ise yuksekligi kac cm? (pi=3)", "secenekler": ["A) 32/3", "B) 128/3", "C) 512/48", "D) 256/6"], "cevap": 0, "konu": "Geometrik Cisimler", "aciklama": "Kup V=512. pi x r^2 x h = 512. 3 x 16 x h = 512. h = 512/48 = 32/3 cm."},
    {"soru": "Koninin taban yaricapi ve yuksekligi esit (r=h=6 cm). Hacmi kac cm^3? (pi=3)", "secenekler": ["A) 72", "B) 108", "C) 144", "D) 216"], "cevap": 1, "konu": "Geometrik Cisimler", "aciklama": "V=1/3 x pi x r^2 x h = 1/3 x 3 x 36 x 6 = 108 cm^3."},
    {"soru": "Bir dikdortgenler prizmasinin 3 farkli yuzunun alanlari 12, 15, 20 cm^2 ise hacmi kac cm^3?", "secenekler": ["A) 30", "B) 45", "C) 60", "D) 75"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "ab=12, bc=15, ac=20. (abc)^2=12x15x20=3600. abc=60 cm^3."},
    {"soru": "Yaricapi 2 cm olan 8 kure eritilip tek kure yapildi. Yeni kurenin yaricapi kac cm?", "secenekler": ["A) 2", "B) 3", "C) 4", "D) 8"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "8 x (4/3)pi(2)^3 = (4/3)pi(R)^3. 8x8=R^3. R^3=64. R=4 cm."},
    {"soru": "Bir prizmanin 7 yuzeysi varsa taban sekli kac gendir?", "secenekler": ["A) 3", "B) 4", "C) 5", "D) 6"], "cevap": 2, "konu": "Geometrik Cisimler", "aciklama": "Prizmanin yuz sayisi=n+2 (n: taban kenar sayisi). n+2=7, n=5. Besgen."},
